{"code":"import json

with open(locals()['var_function-call-4672195044827894195'], 'r') as f:
    papers = json.load(f)

keywords = ['food', 'eating', 'diet', 'nutrition']
hits = {}

for p in papers:
    text = p.get('text', '').lower()
    title = p.get('filename', '')
    found = [k for k in keywords if k in text]
    if found:
        hits[title] = found

